8	import AppKit
9	
10	final class SquirrelPanel: NSPanel {
11	  private let view: SquirrelView
12	  private let back: NSView
13	  var inputController: SquirrelInputController?
14	
15	  var position: NSRect
16	  private var screenRect: NSRect = .zero
17	  private var maxHeight: CGFloat = 0
18	
19	  private var statusMessage: String = ""
20	  private var statusTimer: Timer?
21	
22	  private var preedit: String = ""
23	  private var selRange: NSRange = .empty
24	  private var caretPos: Int = 0
25	  private var candidates: [String] = .init()
26	  private var comments: [String] = .init()
27	  private var labels: [String] = .init()
28	  private var index: Int = 0
29	  private var cursorIndex: Int = 0
30	  private var scrollDirection: CGVector = .zero
31	  private var scrollTime: Date = .distantPast
32	  private var page: Int = 0
33	  private var lastPage: Bool = true
34	  private var pagingUp: Bool?
35	
36	  init(position: NSRect) {
37	    self.position = position
38	    self.view = SquirrelView(frame: position)
39	    self.back = Self.makeBackgroundView()
40	    super.init(contentRect: position, styleMask: .nonactivatingPanel, backing: .buffered, defer: true)
41	    self.level = .init(Int(CGShieldingWindowLevel()))
42	    self.hasShadow = true
43	    self.isOpaque = false
44	    self.backgroundColor = .clear
45	    back.wantsLayer = true
46	    back.layer?.mask = view.shape
47	    let contentView = NSView()
48	    contentView.addSubview(back)
49	    contentView.addSubview(view)
50	    contentView.addSubview(view.textView)
51	    self.contentView = contentView
52	  }
53	
54	  var linear: Bool {
55	    view.currentTheme.linear
56	  }
57	  var vertical: Bool {
58	    view.currentTheme.vertical
59	  }
60	  var inlinePreedit: Bool {
61	    view.currentTheme.inlinePreedit
62	  }
63	  var inlineCandidate: Bool {
64	    view.currentTheme.inlineCandidate
65	  }
66	
67	  // swiftlint:disable:next cyclomatic_complexity
68	  override func sendEvent(_ event: NSEvent) {
69	    switch event.type {
70	    case .leftMouseDown:
71	      let (index, _, pagingUp) =  view.click(at: mousePosition())
72	      if let pagingUp {
73	        self.pagingUp = pagingUp
74	      } else {
75	        self.pagingUp = nil
76	      }
77	      if let index, index >= 0 && index < candidates.count {
78	        self.index = index
79	      }
80	    case .leftMouseUp:
81	      let (index, preeditIndex, pagingUp) = view.click(at: mousePosition())
82	
83	      if let pagingUp, pagingUp == self.pagingUp {
84	        _ = inputController?.page(up: pagingUp)
85	      } else {
86	        self.pagingUp = nil
87	      }
88	      if let preeditIndex, preeditIndex >= 0 && preeditIndex < preedit.utf16.count {
89	        if preeditIndex < caretPos {
90	          _ = inputController?.moveCaret(forward: true)
91	        } else if preeditIndex > caretPos {
92	          _ = inputController?.moveCaret(forward: false)
93	        }
94	      }
95	      if let index, index == self.index && index >= 0 && index < candidates.count {
96	        _ = inputController?.selectCandidate(index)
97	      }
98	    case .mouseEntered:
99	      acceptsMouseMovedEvents = true
100	    case .mouseExited:
101	      acceptsMouseMovedEvents = false
102	      if cursorIndex != index {
103	        update(preedit: preedit, selRange: selRange, caretPos: caretPos, candidates: candidates, comments: comments, labels: labels, highlighted: index, page: page, lastPage: lastPage, update: false)
104	      }
105	      pagingUp = nil
106	    case .mouseMoved:
107	      let (index, _, _) = view.click(at: mousePosition())
108	      if let index = index, cursorIndex != index && index >= 0 && index < candidates.count {
109	        update(preedit: preedit, selRange: selRange, caretPos: caretPos, candidates: candidates, comments: comments, labels: labels, highlighted: index, page: page, lastPage: lastPage, update: false)
110	      }
111	    case .scrollWheel:
112	      if event.phase == .began {
113	        scrollDirection = .zero
114	      } else if event.phase == .ended || (event.phase == .init(rawValue: 0) && event.momentumPhase != .init(rawValue: 0)) {
115	        if abs(scrollDirection.dx) > abs(scrollDirection.dy) && abs(scrollDirection.dx) > 10 {
116	          _ = inputController?.page(up: (scrollDirection.dx < 0) == vertical)
117	        } else if abs(scrollDirection.dx) < abs(scrollDirection.dy) && abs(scrollDirection.dy) > 10 {
118	          _ = inputController?.page(up: scrollDirection.dy > 0)
119	        }
120	        scrollDirection = .zero
121	      } else if event.phase == .init(rawValue: 0) && event.momentumPhase == .init(rawValue: 0) {
122	        if scrollTime.timeIntervalSinceNow < -1 {
123	          scrollDirection = .zero
124	        }
125	        scrollTime = .now
126	        if (scrollDirection.dy >= 0 && event.scrollingDeltaY > 0) || (scrollDirection.dy <= 0 && event.scrollingDeltaY < 0) {
127	          scrollDirection.dy += event.scrollingDeltaY
128	        } else {
129	          scrollDirection = .zero
130	        }
131	        if abs(scrollDirection.dy) > 10 {
132	          _ = inputController?.page(up: scrollDirection.dy > 0)
133	          scrollDirection = .zero
134	        }
135	      } else {
136	        scrollDirection.dx += event.scrollingDeltaX
137	        scrollDirection.dy += event.scrollingDeltaY
138	      }
139	    default:
140	      break
141	    }
142	    super.sendEvent(event)
143	  }
144	
145	  func hide() {
146	    statusTimer?.invalidate()
147	    statusTimer = nil
148	    orderOut(nil)
149	    maxHeight = 0
150	  }
151	
152	  // swiftlint:disable:next cyclomatic_complexity function_parameter_count
153	  func update(preedit: String, selRange: NSRange, caretPos: Int, candidates: [String], comments: [String], labels: [String], highlighted index: Int, page: Int, lastPage: Bool, update: Bool) {
154	    if update {
155	      self.preedit = preedit
156	      self.selRange = selRange
157	      self.caretPos = caretPos
158	      self.candidates = candidates
159	      self.comments = comments
160	      self.labels = labels
161	      self.index = index
162	      self.page = page
163	      self.lastPage = lastPage
164	    }
165	    cursorIndex = index
166	
167	    if !candidates.isEmpty || !preedit.isEmpty {
168	      statusMessage = ""
169	      statusTimer?.invalidate()
170	      statusTimer = nil
171	    } else {
172	      if !statusMessage.isEmpty {
173	        show(status: statusMessage)
174	        statusMessage = ""
175	      } else if statusTimer == nil {
176	        hide()
177	      }
178	      return
179	    }
180	
181	    let theme = view.currentTheme
182	    currentScreen()
183	
184	    let text = NSMutableAttributedString()
185	    let preeditRange: NSRange
186	    let highlightedPreeditRange: NSRange
187	
188	    if !preedit.isEmpty {
189	      preeditRange = NSRange(location: 0, length: preedit.utf16.count)
190	      highlightedPreeditRange = selRange
191	
192	      let line = NSMutableAttributedString(string: preedit)
193	      line.addAttributes(theme.preeditAttrs, range: preeditRange)
194	      line.addAttributes(theme.preeditHighlightedAttrs, range: selRange)
195	      text.append(line)
196	
197	      text.addAttribute(.paragraphStyle, value: theme.preeditParagraphStyle, range: NSRange(location: 0, length: text.length))
198	      if !candidates.isEmpty {
199	        text.append(NSAttributedString(string: "\n", attributes: theme.preeditAttrs))
200	      }
201	    } else {
202	      preeditRange = .empty
203	      highlightedPreeditRange = .empty
204	    }
205	
206	    var candidateRanges = [NSRange]()
207	    for i in 0..<candidates.count {
208	      let attrs = i == index ? theme.highlightedAttrs : theme.attrs
209	      let labelAttrs = i == index ? theme.labelHighlightedAttrs : theme.labelAttrs
210	      let commentAttrs = i == index ? theme.commentHighlightedAttrs : theme.commentAttrs
211	
212	      let label = if theme.candidateFormat.contains(/\[label\]/) {
213	        if labels.count > 1 && i < labels.count {
214	          labels[i]
215	        } else if labels.count == 1 && i < labels.first!.count {
216	          String(labels.first![labels.first!.index(labels.first!.startIndex, offsetBy: i)])
217	        } else {
218	          "\(i+1)"
219	        }
220	      } else {
221	        ""
222	      }
223	
224	      let candidate = candidates[i].precomposedStringWithCanonicalMapping
225	      let comment = comments[i].precomposedStringWithCanonicalMapping
226	
227	      let line = NSMutableAttributedString(string: theme.candidateFormat, attributes: labelAttrs)
228	      for range in line.string.ranges(of: /\[candidate\]/) {
229	        let convertedRange = convert(range: range, in: line.string)
230	        line.addAttributes(attrs, range: convertedRange)
231	        if candidate.count <= 5 {
232	          line.addAttribute(.noBreak, value: true, range: NSRange(location: convertedRange.location+1, length: convertedRange.length-1))
233	        }
234	      }
235	      for range in line.string.ranges(of: /\[comment\]/) {
236	        let convertedRange = convert(range: range, in: line.string)
237	        // Apply semantic accent/warning colors only for non-highlighted rows
238	        if let inputController, !inputController.specialCommentIndices.isEmpty && i != index {
239	          var newCommentAttrs = commentAttrs
240	          if let accent = inputController.specialCommentIndices[.commentHighlight], accent.contains(i) {
241	            newCommentAttrs[.foregroundColor] = theme.accentCommentTextColor
242	          } else if let warning = inputController.specialCommentIndices[.commentWarning], warning.contains(i) {
243	            newCommentAttrs[.foregroundColor] = theme.warningCommentTextColor
244	          }
245	          line.addAttributes(newCommentAttrs, range: convertedRange)
246	        } else {
247	          line.addAttributes(commentAttrs, range: convertedRange)
248	        }
249	      }
250	      line.mutableString.replaceOccurrences(of: "[label]", with: label, range: NSRange(location: 0, length: line.length))
251	      let labeledLine = line.copy() as! NSAttributedString
252	      line.mutableString.replaceOccurrences(of: "[candidate]", with: candidate, range: NSRange(location: 0, length: line.length))
253	      line.mutableString.replaceOccurrences(of: "[comment]", with: comment, range: NSRange(location: 0, length: line.length))
254	
255	      if line.length <= 10 {
256	        line.addAttribute(.noBreak, value: true, range: NSRange(location: 1, length: line.length-1))
257	      }
258	
259	      let lineSeparator = NSAttributedString(string: linear ? "  " : "\n", attributes: attrs)
260	      if i > 0 {
261	        text.append(lineSeparator)
262	      }
263	      let str = lineSeparator.mutableCopy() as! NSMutableAttributedString
264	      if vertical {
265	        str.addAttribute(.verticalGlyphForm, value: 1, range: NSRange(location: 0, length: str.length))
266	      }
267	      view.separatorWidth = str.boundingRect(with: .zero).width
268	
269	      let paragraphStyleCandidate = (i == 0 ? theme.firstParagraphStyle : theme.paragraphStyle).mutableCopy() as! NSMutableParagraphStyle
270	      if linear {
271	        paragraphStyleCandidate.paragraphSpacingBefore -= theme.linespace
272	        paragraphStyleCandidate.lineSpacing = theme.linespace
273	      }
274	      if !linear, let labelEnd = labeledLine.string.firstMatch(of: /\[(candidate|comment)\]/)?.range.lowerBound {
275	        let labelString = labeledLine.attributedSubstring(from: NSRange(location: 0, length: labelEnd.utf16Offset(in: labeledLine.string)))
276	        let labelWidth = labelString.boundingRect(with: .zero, options: [.usesLineFragmentOrigin]).width
277	        paragraphStyleCandidate.headIndent = labelWidth
278	      }
279	      line.addAttribute(.paragraphStyle, value: paragraphStyleCandidate, range: NSRange(location: 0, length: line.length))
280	
281	      candidateRanges.append(NSRange(location: text.length, length: line.length))
282	      text.append(line)
283	    }
284	
285	    view.textView.textContentStorage?.attributedString = text
286	    view.textView.setLayoutOrientation(vertical ? .vertical : .horizontal)
287	
288	    // Force TextKit 2 layout before measuring wrapped text and highlight bounds.
289	    let textWidth = maxTextWidth()
290	    let maxTextHeight = vertical ? screenRect.width - theme.edgeInset.width * 2 : screenRect.height - theme.edgeInset.height * 2
291	    view.textContainer.size = NSSize(width: textWidth, height: maxTextHeight)
292	    view.textLayoutManager.ensureLayout(for: view.textLayoutManager.documentRange)
293	
294	    // Keep very tall wrapped text from auto-scrolling past the first line.
295	    view.textView.scrollToBeginningOfDocument(nil)
296	
297	    view.drawView(candidateRanges: candidateRanges, hilightedIndex: index, preeditRange: preeditRange, highlightedPreeditRange: highlightedPreeditRange, canPageUp: page > 0, canPageDown: !lastPage)
298	    show()
299	  }
300	
301	  func updateStatus(long longMessage: String, short shortMessage: String) {
302	    let theme = view.currentTheme
303	    switch theme.statusMessageType {
304	    case .mix:
305	      statusMessage = shortMessage.isEmpty ? longMessage : shortMessage
306	    case .long:
307	      statusMessage = longMessage
308	    case .short:
309	      if !shortMessage.isEmpty {
310	        statusMessage = shortMessage
311	      } else if let initial = longMessage.first {
312	        statusMessage = String(initial)
313	      } else {
314	        statusMessage = ""
315	      }
316	    }
317	  }
318	
319	  func load(config: SquirrelConfig, forDarkMode isDark: Bool) {
320	    if isDark {
321	      view.darkTheme = SquirrelTheme()
322	      view.darkTheme.load(config: config, dark: true)
323	    } else {
324	      view.lightTheme = SquirrelTheme()
325	      view.lightTheme.load(config: config, dark: isDark)
326	    }
327	  }
328	}
329	
330	private extension SquirrelPanel {
331	  func mousePosition() -> NSPoint {
332	    var point = NSEvent.mouseLocation
333	    point = self.convertPoint(fromScreen: point)
334	    return view.convert(point, from: nil)
335	  }
336	
337	  func currentScreen() {
338	    if let screen = NSScreen.main {
339	      screenRect = screen.frame
340	    }
341	    for screen in NSScreen.screens where screen.frame.contains(position.origin) {
342	      screenRect = screen.frame
343	      break
344	    }
345	  }
346	
347	  func maxTextWidth() -> CGFloat {
348	    let theme = view.currentTheme
349	    let font: NSFont = theme.font
350	    let fontScale = font.pointSize / 12
351	    let textWidthRatio = min(1, 1 / (vertical ? 4 : 3) + fontScale / 12)
352	    let maxWidth = if vertical {
353	      screenRect.height * textWidthRatio - theme.edgeInset.height * 2
354	    } else {
355	      screenRect.width * textWidthRatio - theme.edgeInset.width * 2
356	    }
357	    return maxWidth
358	  }
359	
360	  // swiftlint:disable:next cyclomatic_complexity
361	  func show() {
362	    currentScreen()
363	    let theme = view.currentTheme
364	    if theme.native || view.darkTheme.available {
365	      self.appearance = NSApp.effectiveAppearance
366	    } else {
367	      // user configured only a light theme, set window appearance to light.
368	      self.appearance = NSAppearance(named: .aqua)
369	    }
370	
371	    view.textView.textContainerInset = theme.edgeInset
372	
373	    var textWidth = maxTextWidth()
374	    // Measure natural text height before constraining the panel.
375	    view.textContainer.size = NSSize(width: textWidth, height: .greatestFiniteMagnitude)
376	
377	    // Do not let NSTextView shrink the container to the current view width; it can loop or hide text.
378	    view.textContainer.widthTracksTextView = false
379	    view.textContainer.heightTracksTextView = false
380	
381	    view.textLayoutManager.ensureLayout(for: view.textLayoutManager.documentRange)
382	    view.textView.bounds.origin = .zero
383	
384	    var contentRect = view.contentRect
385	
386	    // Compute the largest size possible for a giant panel
387	    var naturalPanelSize = NSSize.zero
388	    if vertical {
389	      naturalPanelSize.width = contentRect.height + theme.edgeInset.height * 2
390	      naturalPanelSize.height = contentRect.width + theme.edgeInset.width * 2 + theme.pagingOffset
391	    } else {
392	      naturalPanelSize.width = contentRect.width + theme.edgeInset.width * 2 + theme.pagingOffset
393	      naturalPanelSize.height = contentRect.height + theme.edgeInset.height * 2
394	    }
395	
396	    let maxAllowedWidth = screenRect.width * 0.95
397	    let maxAllowedHeight = screenRect.height * 0.95
398	
399	    let requiresFullScreen = naturalPanelSize.width > maxAllowedWidth || naturalPanelSize.height > maxAllowedHeight
400	
401	    if requiresFullScreen {
402	      // Expand line length before fullscreen scaling to avoid wasting screen space on narrow text.
403	      let area = contentRect.width * contentRect.height
404	      let screenRatio = maxAllowedWidth / maxAllowedHeight
405	
406	      let optimalTextWidth: CGFloat
407	      if vertical {
408	        // Width = screen height in vertical mode
409	        optimalTextWidth = sqrt(area / screenRatio)
410	      } else {
411	        optimalTextWidth = sqrt(area * screenRatio)
412	      }
413	
414	      // If there's extra room for text, tighten the layout
415	      if optimalTextWidth > textWidth {
416	        textWidth = optimalTextWidth
417	        view.textContainer.size = NSSize(width: textWidth, height: .greatestFiniteMagnitude)
418	        view.textLayoutManager.ensureLayout(for: view.textLayoutManager.documentRange)
419	
420	        contentRect = view.contentRect
421	
422	        if vertical {
423	          naturalPanelSize.width = contentRect.height + theme.edgeInset.height * 2
424	          naturalPanelSize.height = contentRect.width + theme.edgeInset.width * 2 + theme.pagingOffset
425	        } else {
426	          naturalPanelSize.width = contentRect.width + theme.edgeInset.width * 2 + theme.pagingOffset
427	          naturalPanelSize.height = contentRect.height + theme.edgeInset.height * 2
428	        }
429	      }
430	    }
431	
432	    var panelRect = NSRect.zero
433	
434	    if requiresFullScreen {
435	      let scaleX = maxAllowedWidth / naturalPanelSize.width
436	      let scaleY = maxAllowedHeight / naturalPanelSize.height
437	      let scale = min(scaleX, scaleY)
438	
439	      panelRect.size = NSSize(width: naturalPanelSize.width * scale, height: naturalPanelSize.height * scale)
440	
441	      panelRect.origin = NSPoint(
442	        x: screenRect.minX + (screenRect.width - panelRect.width) / 2,
443	        y: screenRect.minY + (screenRect.height - panelRect.height) / 2
444	      )
445	
446	      maxHeight = 0
447	    } else {
448	      if theme.memorizeSize && (vertical && position.midY / screenRect.height < 0.5) ||
449	          (vertical && position.minX + max(contentRect.width, maxHeight) + theme.edgeInset.width * 2 > screenRect.maxX) {
450	        if contentRect.width >= maxHeight {
451	          maxHeight = contentRect.width
452	        } else {
453	          contentRect.size.width = maxHeight
454	          if vertical {
455	            naturalPanelSize.height = contentRect.width + theme.edgeInset.width * 2 + theme.pagingOffset
456	          } else {
457	            naturalPanelSize.width = contentRect.width + theme.edgeInset.width * 2 + theme.pagingOffset
458	          }
459	        }
460	      }
461	
462	      panelRect.size = naturalPanelSize
463	
464	      if vertical {
465	        // Anchor vertical panels on one side of the cursor to avoid jumping while typing.
466	        if position.midY / screenRect.height >= 0.5 {
467	          panelRect.origin.y = position.minY - SquirrelTheme.offsetHeight - panelRect.height + theme.pagingOffset
468	        } else {
469	          panelRect.origin.y = position.maxY + SquirrelTheme.offsetHeight
470	        }
471	        panelRect.origin.x = position.minX - panelRect.width - SquirrelTheme.offsetHeight
472	        if view.preeditRange.length > 0, let preeditTextRange = view.convert(range: view.preeditRange) {
473	          let preeditRect = view.contentRect(range: preeditTextRange)
474	          panelRect.origin.x += preeditRect.height + theme.edgeInset.width
475	        }
476	      } else {
477	        panelRect.origin = NSPoint(x: position.minX - theme.pagingOffset, y: position.minY - SquirrelTheme.offsetHeight - panelRect.height)
478	      }
479	
480	      if panelRect.maxX > screenRect.maxX { panelRect.origin.x = screenRect.maxX - panelRect.width }
481	      if panelRect.minX < screenRect.minX { panelRect.origin.x = screenRect.minX }
482	      if panelRect.minY < screenRect.minY {
483	        if vertical { panelRect.origin.y = screenRect.minY } else { panelRect.origin.y = position.maxY + SquirrelTheme.offsetHeight }
484	      }
485	      if panelRect.maxY > screenRect.maxY { panelRect.origin.y = screenRect.maxY - panelRect.height }
486	      if panelRect.minY < screenRect.minY { panelRect.origin.y = screenRect.minY }
487	    }
488	
489	    self.setFrame(panelRect, display: true)
490	
491	    // Keep the window frame at the scaled physical size while drawing in natural coordinates through bounds.
492	    contentView!.frame = NSRect(origin: .zero, size: panelRect.size)
493	    contentView!.bounds = NSRect(origin: .zero, size: naturalPanelSize)
494	
495	    if vertical {
496	      contentView!.boundsRotation = -90
497	      contentView!.setBoundsOrigin(NSPoint(x: 0, y: naturalPanelSize.width))
498	    } else {
499	      contentView!.boundsRotation = 0
500	      contentView!.setBoundsOrigin(.zero)
501	    }
502	
503	    view.textView.boundsRotation = 0
504	    view.textView.setBoundsOrigin(.zero)
505	
506	    // Subviews must read the post-rotation bounds; Cocoa adjusts the origin and swaps dimensions in vertical mode.
507	    let subviewFrame = contentView!.bounds
508	    view.frame = subviewFrame
509	
510	    var textFrame = subviewFrame
511	    textFrame.size.width -= theme.pagingOffset
512	    textFrame.origin.x += theme.pagingOffset
513	    view.textView.frame = textFrame
514	
515	    if theme.translucency {
516	      var backFrame = subviewFrame
517	      backFrame.size.width += theme.pagingOffset
518	      back.frame = backFrame
519	      back.appearance = NSApp.effectiveAppearance
520	      back.isHidden = false
521	    } else {
522	      back.isHidden = true
523	    }
524	
525	    alphaValue = theme.alpha
526	    invalidateShadow()
527	    orderFront(nil)
528	    // voila!
529	  }
530	
531	  func show(status message: String) {
532	    let theme = view.currentTheme
533	    let text = NSMutableAttributedString(string: message, attributes: theme.attrs)
534	    text.addAttribute(.paragraphStyle, value: theme.paragraphStyle, range: NSRange(location: 0, length: text.length))
535	    view.textContentStorage.attributedString = text
536	    view.textView.setLayoutOrientation(vertical ? .vertical : .horizontal)
537	    view.drawView(candidateRanges: [NSRange(location: 0, length: text.length)], hilightedIndex: -1,
538	                  preeditRange: .empty, highlightedPreeditRange: .empty, canPageUp: false, canPageDown: false)
539	    show()
540	
541	    statusTimer?.invalidate()
542	    statusTimer = Timer.scheduledTimer(withTimeInterval: SquirrelTheme.showStatusDuration, repeats: false) { _ in
543	      self.hide()
544	    }
545	  }
546	
547	  func convert(range: Range<String.Index>, in string: String) -> NSRange {
548	    let startPos = range.lowerBound.utf16Offset(in: string)
549	    let endPos = range.upperBound.utf16Offset(in: string)
550	    return NSRange(location: startPos, length: endPos - startPos)
551	  }
552	
553	  static func makeBackgroundView() -> NSView {
554	    if #available(macOS 26.0, *) {
555	      let glassView = NSGlassEffectView()
556	      glassView.style = .clear
557	      return glassView
558	    } else {
559	      let visualEffectView = NSVisualEffectView()
560	      visualEffectView.blendingMode = .behindWindow
561	      visualEffectView.material = .hudWindow
562	      visualEffectView.state = .active
563	      return visualEffectView
564	    }
565	  }
566	}
