10	private class SquirrelLayoutDelegate: NSObject, NSTextLayoutManagerDelegate {
11	  func textLayoutManager(_ textLayoutManager: NSTextLayoutManager, shouldBreakLineBefore location: any NSTextLocation, hyphenating: Bool) -> Bool {
12	    let index = textLayoutManager.offset(from: textLayoutManager.documentRange.location, to: location)
13	    if let attributes = textLayoutManager.textContainer?.textView?.textContentStorage?.attributedString?.attributes(at: index, effectiveRange: nil),
14	       let noBreak = attributes[.noBreak] as? Bool, noBreak {
15	      return false
16	    }
17	    return true
18	  }
19	}
