25	final class SquirrelView: NSView {
26	  let textView: NSTextView
27	
28	  private let squirrelLayoutDelegate: SquirrelLayoutDelegate
29	  var candidateRanges: [NSRange] = []
30	  var hilightedIndex = 0
31	  var preeditRange: NSRange = .empty
32	  var canPageUp: Bool = false
33	  var canPageDown: Bool = false
34	  var highlightedPreeditRange: NSRange = .empty
35	  var separatorWidth: CGFloat = 0
36	  var shape = CAShapeLayer()
37	  private var downPath: CGPath?
38	  private var upPath: CGPath?
39	
40	  var lightTheme = SquirrelTheme()
41	  var darkTheme = SquirrelTheme()
42	  var currentTheme: SquirrelTheme {
43	    if isDark && darkTheme.available { darkTheme } else { lightTheme }
44	  }
45	  var textLayoutManager: NSTextLayoutManager {
46	    textView.textLayoutManager!
47	  }
48	  var textContentStorage: NSTextContentStorage {
49	    textView.textContentStorage!
50	  }
51	  var textContainer: NSTextContainer {
52	    textLayoutManager.textContainer!
53	  }
54	
55	  override init(frame frameRect: NSRect) {
56	    squirrelLayoutDelegate = SquirrelLayoutDelegate()
57	    textView = NSTextView(frame: frameRect)
58	    textView.drawsBackground = false
59	    textView.isEditable = false
60	    textView.isSelectable = false
61	    textView.textLayoutManager?.delegate = squirrelLayoutDelegate
62	    super.init(frame: frameRect)
63	    textContainer.lineFragmentPadding = 0
64	    self.wantsLayer = true
65	    self.layer?.masksToBounds = true
66	  }
67	  required init?(coder: NSCoder) {
68	    fatalError("init(coder:) has not been implemented")
69	  }
70	
71	  override var isFlipped: Bool {
72	    true
73	  }
74	  var isDark: Bool {
75	    NSApp.effectiveAppearance.bestMatch(from: [.aqua, .darkAqua]) == .darkAqua
76	  }
77	
78	  func convert(range: NSRange) -> NSTextRange? {
79	    guard range != .empty else { return nil }
80	    guard let startLocation = textLayoutManager.location(textLayoutManager.documentRange.location, offsetBy: range.location) else { return nil }
81	    guard let endLocation = textLayoutManager.location(startLocation, offsetBy: range.length) else { return nil }
82	    return NSTextRange(location: startLocation, end: endLocation)
83	  }
84	
85	  var contentRect: NSRect {
86	    var ranges = candidateRanges
87	    if preeditRange.length > 0 {
88	      ranges.append(preeditRange)
89	    }
90	    // swiftlint:disable:next identifier_name
91	    var x0 = CGFloat.infinity, x1 = -CGFloat.infinity, y0 = CGFloat.infinity, y1 = -CGFloat.infinity
92	    for range in ranges {
93	      if let textRange = convert(range: range) {
94	        let rect = contentRect(range: textRange)
95	        x0 = min(rect.minX, x0)
96	        x1 = max(rect.maxX, x1)
97	        y0 = min(rect.minY, y0)
98	        y1 = max(rect.maxY, y1)
99	      }
100	    }
101	    if x1 == -CGFloat.infinity { return .zero }
102	    return NSRect(x: min(0, x0), y: min(0, y0), width: x1 - min(0, x0), height: y1 - min(0, y0))
103	  }
104	
105	  func contentRect(range: NSTextRange) -> NSRect {
106	    // swiftlint:disable:next identifier_name
107	    var x0 = CGFloat.infinity, x1 = -CGFloat.infinity, y0 = CGFloat.infinity, y1 = -CGFloat.infinity
108	    textLayoutManager.enumerateTextSegments(in: range, type: .selection, options: [.rangeNotRequired]) { _, rect, _, _ in
109	      x0 = min(rect.minX, x0)
110	      x1 = max(rect.maxX, x1)
111	      y0 = min(rect.minY, y0)
112	      y1 = max(rect.maxY, y1)
113	      return true
114	    }
115	    return NSRect(x: x0, y: y0, width: x1-x0, height: y1-y0)
116	  }
