118	  // swiftlint:disable:next function_parameter_count
119	  func drawView(candidateRanges: [NSRange], hilightedIndex: Int, preeditRange: NSRange, highlightedPreeditRange: NSRange, canPageUp: Bool, canPageDown: Bool) {
120	    self.candidateRanges = candidateRanges
121	    self.hilightedIndex = hilightedIndex
122	    self.preeditRange = preeditRange
123	    self.highlightedPreeditRange = highlightedPreeditRange
124	    self.canPageUp = canPageUp
125	    self.canPageDown = canPageDown
126	    self.needsDisplay = true
127	  }
