129	  // swiftlint:disable:next cyclomatic_complexity
130	  override func draw(_ dirtyRect: NSRect) {
131	    var backgroundPath: CGPath?
132	    var preeditPath: CGPath?
133	    var candidatePaths: CGMutablePath?
134	    var highlightedPath: CGMutablePath?
135	    var highlightedPreeditPath: CGMutablePath?
136	    let theme = currentTheme
137	
138	    var containingRect = self.bounds
139	    containingRect.size.width -= theme.pagingOffset
140	    let backgroundRect = containingRect
141	
142	    var preeditRect = NSRect.zero
143	    if preeditRange.length > 0, let preeditTextRange = convert(range: preeditRange) {
144	      preeditRect = contentRect(range: preeditTextRange)
145	      preeditRect.size.width = backgroundRect.size.width
146	      preeditRect.size.height += theme.edgeInset.height + theme.preeditLinespace / 2 + theme.hilitedCornerRadius / 2
147	      preeditRect.origin = backgroundRect.origin
148	      if candidateRanges.count == 0 {
149	        preeditRect.size.height += theme.edgeInset.height - theme.preeditLinespace / 2 - theme.hilitedCornerRadius / 2
150	      }
151	      containingRect.size.height -= preeditRect.size.height
152	      containingRect.origin.y += preeditRect.size.height
153	      if theme.preeditBackgroundColor != nil {
154	        preeditPath = drawSmoothLines(rectVertex(of: preeditRect), straightCorner: Set(), alpha: 0, beta: 0)
155	      }
156	    }
157	
158	    containingRect = carveInset(rect: containingRect)
159	    for i in 0..<candidateRanges.count {
160	      let candidate = candidateRanges[i]
161	      if i == hilightedIndex {
162	        if candidate.length > 0 && theme.highlightedBackColor != nil {
163	          highlightedPath = drawPath(highlightedRange: candidate, backgroundRect: backgroundRect, preeditRect: preeditRect, containingRect: containingRect, extraExpansion: 0)?.mutableCopy()
164	        }
165	      } else {
166	        if candidate.length > 0 && theme.candidateBackColor != nil {
167	          let candidatePath = drawPath(highlightedRange: candidate, backgroundRect: backgroundRect, preeditRect: preeditRect,
168	                                       containingRect: containingRect, extraExpansion: theme.surroundingExtraExpansion)
169	          if candidatePaths == nil {
170	            candidatePaths = CGMutablePath()
171	          }
172	          if let candidatePath = candidatePath {
173	            candidatePaths?.addPath(candidatePath)
174	          }
175	        }
176	      }
177	    }
178	
179	    if (highlightedPreeditRange.length > 0) && (theme.highlightedPreeditColor != nil), let highlightedPreeditTextRange = convert(range: highlightedPreeditRange) {
180	      var innerBox = preeditRect
181	      innerBox.size.width -= (theme.edgeInset.width + 1) * 2
182	      innerBox.origin.x += theme.edgeInset.width + 1
183	      innerBox.origin.y += theme.edgeInset.height + 1
184	      if candidateRanges.count == 0 {
185	        innerBox.size.height -= (theme.edgeInset.height + 1) * 2
186	      } else {
187	        innerBox.size.height -= theme.edgeInset.height + theme.preeditLinespace / 2 + theme.hilitedCornerRadius / 2 + 2
188	      }
189	      var outerBox = preeditRect
190	      outerBox.size.height -= max(0, theme.hilitedCornerRadius + theme.borderLineWidth)
191	      outerBox.size.width -= max(0, theme.hilitedCornerRadius + theme.borderLineWidth)
192	      outerBox.origin.x += max(0, theme.hilitedCornerRadius + theme.borderLineWidth) / 2
193	      outerBox.origin.y += max(0, theme.hilitedCornerRadius + theme.borderLineWidth) / 2
194	
195	      let (leadingRect, bodyRect, trailingRect) = multilineRects(forRange: highlightedPreeditTextRange, extraSurounding: 0, bounds: outerBox)
196	      var (highlightedPoints, highlightedPoints2, rightCorners, rightCorners2) = linearMultilineFor(body: bodyRect, leading: leadingRect, trailing: trailingRect)
197	
198	      containingRect = carveInset(rect: preeditRect)
199	      highlightedPoints = expand(vertex: highlightedPoints, innerBorder: innerBox, outerBorder: outerBox)
200	      rightCorners = removeCorner(highlightedPoints: highlightedPoints, rightCorners: rightCorners, containingRect: containingRect)
201	      highlightedPreeditPath = drawSmoothLines(highlightedPoints, straightCorner: rightCorners, alpha: 0.3 * theme.hilitedCornerRadius, beta: 1.4 * theme.hilitedCornerRadius)?.mutableCopy()
202	      if highlightedPoints2.count > 0 {
203	        highlightedPoints2 = expand(vertex: highlightedPoints2, innerBorder: innerBox, outerBorder: outerBox)
204	        rightCorners2 = removeCorner(highlightedPoints: highlightedPoints2, rightCorners: rightCorners2, containingRect: containingRect)
205	        let highlightedPreeditPath2 = drawSmoothLines(highlightedPoints2, straightCorner: rightCorners2, alpha: 0.3 * theme.hilitedCornerRadius, beta: 1.4 * theme.hilitedCornerRadius)
206	        if let highlightedPreeditPath2 = highlightedPreeditPath2 {
207	          highlightedPreeditPath?.addPath(highlightedPreeditPath2)
208	        }
209	      }
210	    }
211	
212	    NSBezierPath.defaultLineWidth = 0
213	    backgroundPath = drawSmoothLines(rectVertex(of: backgroundRect), straightCorner: Set(), alpha: 0.3 * theme.cornerRadius, beta: 1.4 * theme.cornerRadius)
214	
215	    self.layer?.sublayers = nil
216	    let backPath = backgroundPath?.mutableCopy()
217	    if let path = preeditPath {
218	      backPath?.addPath(path)
219	    }
220	    if theme.mutualExclusive {
221	      if let path = highlightedPath {
222	        backPath?.addPath(path)
223	      }
224	      if let path = candidatePaths {
225	        backPath?.addPath(path)
226	      }
227	    }
228	    let panelLayer = shapeFromPath(path: backPath)
229	    panelLayer.fillColor = theme.backgroundColor.cgColor
230	    let panelLayerMask = shapeFromPath(path: backgroundPath)
231	    panelLayer.mask = panelLayerMask
232	    self.layer?.addSublayer(panelLayer)
233	
234	    if let color = theme.preeditBackgroundColor, let path = preeditPath {
235	      let layer = shapeFromPath(path: path)
236	      layer.fillColor = color.cgColor
237	      let maskPath = backgroundPath?.mutableCopy()
238	      if theme.mutualExclusive, let hilitedPath = highlightedPreeditPath {
239	        maskPath?.addPath(hilitedPath)
240	      }
241	      let mask = shapeFromPath(path: maskPath)
242	      layer.mask = mask
243	      panelLayer.addSublayer(layer)
244	    }
245	    if theme.borderLineWidth > 0, let color = theme.borderColor {
246	      let borderLayer = shapeFromPath(path: backgroundPath)
247	      borderLayer.lineWidth = theme.borderLineWidth * 2
248	      borderLayer.strokeColor = color.cgColor
249	      borderLayer.fillColor = nil
250	      panelLayer.addSublayer(borderLayer)
251	    }
252	    if let color = theme.highlightedPreeditColor, let path = highlightedPreeditPath {
253	      let layer = shapeFromPath(path: path)
254	      layer.fillColor = color.cgColor
255	      panelLayer.addSublayer(layer)
256	    }
257	    if let color = theme.candidateBackColor, let path = candidatePaths {
258	      let layer = shapeFromPath(path: path)
259	      layer.fillColor = color.cgColor
260	      panelLayer.addSublayer(layer)
261	    }
262	    if let color = theme.highlightedBackColor, let path = highlightedPath {
263	      let layer = shapeFromPath(path: path)
264	      layer.fillColor = color.cgColor
265	      if theme.shadowSize > 0 {
266	        let shadowLayer = CAShapeLayer()
267	        shadowLayer.shadowColor = NSColor.black.cgColor
268	        shadowLayer.shadowOffset = NSSize(width: theme.shadowSize/2, height: (theme.vertical ? -1 : 1) * theme.shadowSize/2)
269	        shadowLayer.shadowPath = highlightedPath
270	        shadowLayer.shadowRadius = theme.shadowSize
271	        shadowLayer.shadowOpacity = 0.2
272	        let outerPath = backgroundPath?.mutableCopy()
273	        outerPath?.addPath(path)
274	        let shadowLayerMask = shapeFromPath(path: outerPath)
275	        shadowLayer.mask = shadowLayerMask
276	        layer.strokeColor = NSColor.black.withAlphaComponent(0.15).cgColor
277	        layer.lineWidth = 0.5
278	        layer.addSublayer(shadowLayer)
279	      }
280	      panelLayer.addSublayer(layer)
281	    }
282	    panelLayer.setAffineTransform(CGAffineTransform(translationX: theme.pagingOffset, y: 0))
283	    let panelPath = CGMutablePath()
284	    panelPath.addPath(backgroundPath!, transform: panelLayer.affineTransform().scaledBy(x: 1, y: -1).translatedBy(x: 0, y: -self.bounds.height))
285	
286	    let (pagingLayer, downPath, upPath) = pagingLayer(theme: theme, preeditRect: preeditRect)
287	    if let sublayers = pagingLayer.sublayers, !sublayers.isEmpty {
288	      self.layer?.addSublayer(pagingLayer)
289	    }
290	    let flipTransform = CGAffineTransform(scaleX: 1, y: -1).translatedBy(x: 0, y: -self.bounds.height)
291	    if let downPath {
292	      panelPath.addPath(downPath, transform: flipTransform)
293	      self.downPath = downPath.copy()
294	    }
295	    if let upPath {
296	      panelPath.addPath(upPath, transform: flipTransform)
297	      self.upPath = upPath.copy()
298	    }
299	
300	    shape.path = panelPath
301	  }
