303	  func click(at clickPoint: NSPoint) -> (Int?, Int?, Bool?) {
304	    var index = 0
305	    var candidateIndex: Int?
306	    var preeditIndex: Int?
307	    if let downPath = self.downPath, downPath.contains(clickPoint) {
308	      return (nil, nil, false)
309	    }
310	    if let upPath = self.upPath, upPath.contains(clickPoint) {
311	      return (nil, nil, true)
312	    }
313	    if let path = shape.path, path.contains(clickPoint) {
314	      var point = NSPoint(x: clickPoint.x - textView.textContainerInset.width - currentTheme.pagingOffset,
315	                          y: clickPoint.y - textView.textContainerInset.height)
316	      let fragment = textLayoutManager.textLayoutFragment(for: point)
317	      if let fragment = fragment {
318	        point = NSPoint(x: point.x - fragment.layoutFragmentFrame.minX,
319	                        y: point.y - fragment.layoutFragmentFrame.minY)
320	        index = textLayoutManager.offset(from: textLayoutManager.documentRange.location, to: fragment.rangeInElement.location)
321	        for lineFragment in fragment.textLineFragments where lineFragment.typographicBounds.contains(point) {
322	          point = NSPoint(x: point.x - lineFragment.typographicBounds.minX,
323	                          y: point.y - lineFragment.typographicBounds.minY)
324	          index += lineFragment.characterIndex(for: point)
325	          if index >= preeditRange.location && index < preeditRange.upperBound {
326	            preeditIndex = index
327	          } else {
328	            for i in 0..<candidateRanges.count {
329	              let range = candidateRanges[i]
330	              if index >= range.location && index < range.upperBound {
331	                candidateIndex = i
332	                break
333	              }
334	            }
335	          }
336	          break
337	        }
338	      }
339	    }
340	    return (candidateIndex, preeditIndex, nil)
341	  }
342	}
