344	private extension SquirrelView {
345	  // Soften corner radius when adjacent points are very close.
346	  func sign(_ number: NSPoint) -> NSPoint {
347	    if number.length >= 2 {
348	      return number / number.length
349	    } else {
350	      return number / 2
351	    }
352	  }
353	
354	  // Use cubic Bezier corners for continuous rounded paths.
355	  func drawSmoothLines(_ vertex: [NSPoint], straightCorner: Set<Int>, alpha: CGFloat, beta rawBeta: CGFloat) -> CGPath? {
356	    guard vertex.count >= 3 else {
357	      return nil
358	    }
359	    let beta = max(0.00001, rawBeta)
360	    let path = CGMutablePath()
361	    var previousPoint = vertex[vertex.count-1]
362	    var point = vertex[0]
363	    var nextPoint: NSPoint
364	    var control1: NSPoint
365	    var control2: NSPoint
366	    var target = previousPoint
367	    var diff = point - previousPoint
368	    if straightCorner.isEmpty || !straightCorner.contains(vertex.count-1) {
369	      target += sign(diff / beta) * beta
370	    }
371	    path.move(to: target)
372	    for i in 0..<vertex.count {
373	      previousPoint = vertex[(vertex.count+i-1)%vertex.count]
374	      point = vertex[i]
375	      nextPoint = vertex[(i+1)%vertex.count]
376	      target = point
377	      if straightCorner.contains(i) {
378	        path.addLine(to: target)
379	      } else {
380	        control1 = point
381	        diff = point - previousPoint
382	
383	        target -= sign(diff / beta) * beta
384	        control1 -= sign(diff / beta) * alpha
385	
386	        path.addLine(to: target)
387	        target = point
388	        control2 = point
389	        diff = nextPoint - point
390	
391	        target += sign(diff / beta) * beta
392	        control2 += sign(diff / beta) * alpha
393	
394	        path.addCurve(to: target, control1: control1, control2: control2)
395	      }
396	    }
397	    path.closeSubpath()
398	    return path
399	  }
