401	  func rectVertex(of rect: NSRect) -> [NSPoint] {
402	    [rect.origin,
403	     NSPoint(x: rect.origin.x, y: rect.origin.y+rect.size.height),
404	     NSPoint(x: rect.origin.x+rect.size.width, y: rect.origin.y+rect.size.height),
405	     NSPoint(x: rect.origin.x+rect.size.width, y: rect.origin.y)]
406	  }
407	
408	  func nearEmpty(_ rect: NSRect) -> Bool {
409	    return rect.size.height * rect.size.width < 1
410	  }
411	
412	  // Split a multiline range into leading, complete-body, and trailing boxes.
413	  func multilineRects(forRange range: NSTextRange, extraSurounding: Double, bounds: NSRect) -> (NSRect, NSRect, NSRect) {
414	    let edgeInset = currentTheme.edgeInset
415	    var lineRects = [NSRect]()
416	    textLayoutManager.enumerateTextSegments(in: range, type: .selection, options: [.rangeNotRequired]) { _, rect, _, _ in
417	      var newRect = rect
418	      newRect.origin.x += edgeInset.width
419	      newRect.origin.y += edgeInset.height
420	      newRect.size.height += currentTheme.linespace
421	      newRect.origin.y -= currentTheme.linespace / 2
422	      lineRects.append(newRect)
423	      return true
424	    }
425	
426	    var leadingRect = NSRect.zero
427	    var bodyRect = NSRect.zero
428	    var trailingRect = NSRect.zero
429	    if lineRects.count == 1 {
430	      bodyRect = lineRects[0]
431	    } else if lineRects.count == 2 {
432	      leadingRect = lineRects[0]
433	      trailingRect = lineRects[1]
434	    } else if lineRects.count > 2 {
435	      leadingRect = lineRects[0]
436	      trailingRect = lineRects[lineRects.count-1]
437	      // swiftlint:disable:next identifier_name
438	      var x0 = CGFloat.infinity, x1 = -CGFloat.infinity, y0 = CGFloat.infinity, y1 = -CGFloat.infinity
439	      for i in 1..<(lineRects.count-1) {
440	        let rect = lineRects[i]
441	        x0 = min(rect.minX, x0)
442	        x1 = max(rect.maxX, x1)
443	        y0 = min(rect.minY, y0)
444	        y1 = max(rect.maxY, y1)
445	      }
446	      y0 = min(leadingRect.maxY, y0)
447	      y1 = max(trailingRect.minY, y1)
448	      bodyRect = NSRect(x: x0, y: y0, width: x1-x0, height: y1-y0)
449	    }
450	
451	    if extraSurounding > 0 {
452	      if nearEmpty(leadingRect) && nearEmpty(trailingRect) {
453	        bodyRect = expandHighlightWidth(rect: bodyRect, extraSurrounding: extraSurounding)
454	      } else {
455	        if !(nearEmpty(leadingRect)) {
456	          leadingRect = expandHighlightWidth(rect: leadingRect, extraSurrounding: extraSurounding)
457	        }
458	        if !(nearEmpty(trailingRect)) {
459	          trailingRect = expandHighlightWidth(rect: trailingRect, extraSurrounding: extraSurounding)
460	        }
461	      }
462	    }
463	
464	    if !nearEmpty(leadingRect) && !nearEmpty(trailingRect) {
465	      leadingRect.size.width = bounds.maxX - leadingRect.origin.x
466	      trailingRect.size.width = trailingRect.maxX - bounds.minX
467	      trailingRect.origin.x = bounds.minX
468	      if !nearEmpty(bodyRect) {
469	        bodyRect.size.width = bounds.size.width
470	        bodyRect.origin.x = bounds.origin.x
471	      } else {
472	        let diff = trailingRect.minY - leadingRect.maxY
473	        leadingRect.size.height += diff / 2
474	        trailingRect.size.height += diff / 2
475	        trailingRect.origin.y -= diff / 2
476	      }
477	    }
478	
479	    return (leadingRect, bodyRect, trailingRect)
480	  }
481	
482	  // Build the highlight polygon from the multiline text boxes.
483	  func multilineVertex(leadingRect: NSRect, bodyRect: NSRect, trailingRect: NSRect) -> [NSPoint] {
484	    if nearEmpty(bodyRect) && !nearEmpty(leadingRect) && nearEmpty(trailingRect) {
485	      return rectVertex(of: leadingRect)
486	    } else if nearEmpty(bodyRect) && nearEmpty(leadingRect) && !nearEmpty(trailingRect) {
487	      return rectVertex(of: trailingRect)
488	    } else if nearEmpty(leadingRect) && nearEmpty(trailingRect) && !nearEmpty(bodyRect) {
489	      return rectVertex(of: bodyRect)
490	    } else if nearEmpty(trailingRect) && !nearEmpty(bodyRect) {
491	      let leadingVertex = rectVertex(of: leadingRect)
492	      let bodyVertex = rectVertex(of: bodyRect)
493	      return [bodyVertex[0], bodyVertex[1], bodyVertex[2], leadingVertex[3], leadingVertex[0], leadingVertex[1]]
494	    } else if nearEmpty(leadingRect) && !nearEmpty(bodyRect) {
495	      let trailingVertex = rectVertex(of: trailingRect)
496	      let bodyVertex = rectVertex(of: bodyRect)
497	      return [trailingVertex[1], trailingVertex[2], trailingVertex[3], bodyVertex[2], bodyVertex[3], bodyVertex[0]]
498	    } else if !nearEmpty(leadingRect) && !nearEmpty(trailingRect) && nearEmpty(bodyRect) && (leadingRect.maxX>trailingRect.minX) {
499	      let leadingVertex = rectVertex(of: leadingRect)
500	      let trailingVertex = rectVertex(of: trailingRect)
501	      return [trailingVertex[0], trailingVertex[1], trailingVertex[2], trailingVertex[3], leadingVertex[2], leadingVertex[3], leadingVertex[0], leadingVertex[1]]
502	    } else if !nearEmpty(leadingRect) && !nearEmpty(trailingRect) && !nearEmpty(bodyRect) {
503	      let leadingVertex = rectVertex(of: leadingRect)
504	      let bodyVertex = rectVertex(of: bodyRect)
505	      let trailingVertex = rectVertex(of: trailingRect)
506	      return [trailingVertex[1], trailingVertex[2], trailingVertex[3], bodyVertex[2], leadingVertex[3], leadingVertex[0], leadingVertex[1], bodyVertex[0]]
507	    } else {
508	      return [NSPoint]()
509	    }
510	  }
511	
512	  // Clamp points outside the inner border to the outer border.
513	  func expand(vertex: [NSPoint], innerBorder: NSRect, outerBorder: NSRect) -> [NSPoint] {
514	    var newVertex = [NSPoint]()
515	    for i in 0..<vertex.count {
516	      var point = vertex[i]
517	      if point.x < innerBorder.origin.x {
518	        point.x = outerBorder.origin.x
519	      } else if point.x > innerBorder.origin.x+innerBorder.size.width {
520	        point.x = outerBorder.origin.x+outerBorder.size.width
521	      }
522	      if point.y < innerBorder.origin.y {
523	        point.y = outerBorder.origin.y
524	      } else if point.y > innerBorder.origin.y+innerBorder.size.height {
525	        point.y = outerBorder.origin.y+outerBorder.size.height
526	      }
527	      newVertex.append(point)
528	    }
529	    return newVertex
530	  }
