532	  func direction(diff: CGPoint) -> CGPoint {
533	    if diff.y == 0 && diff.x > 0 {
534	      return NSPoint(x: 0, y: 1)
535	    } else if diff.y == 0 && diff.x < 0 {
536	      return NSPoint(x: 0, y: -1)
537	    } else if diff.x == 0 && diff.y > 0 {
538	      return NSPoint(x: -1, y: 0)
539	    } else if diff.x == 0 && diff.y < 0 {
540	      return NSPoint(x: 1, y: 0)
541	    } else {
542	      return NSPoint(x: 0, y: 0)
543	    }
544	  }
