546	  func shapeFromPath(path: CGPath?) -> CAShapeLayer {
547	    let layer = CAShapeLayer()
548	    layer.path = path
549	    layer.fillRule = .evenOdd
550	    return layer
551	  }
552	
553	  // Assumes clockwise iteration
554	  func enlarge(vertex: [NSPoint], by: Double) -> [NSPoint] {
555	    if by != 0 {
556	      var previousPoint: NSPoint
557	      var point: NSPoint
558	      var nextPoint: NSPoint
559	      var results = vertex
560	      var newPoint: NSPoint
561	      var displacement: NSPoint
562	      for i in 0..<vertex.count {
563	        previousPoint = vertex[(vertex.count+i-1) % vertex.count]
564	        point = vertex[i]
565	        nextPoint = vertex[(i+1) % vertex.count]
566	        newPoint = point
567	        displacement = direction(diff: point - previousPoint)
568	        newPoint.x += by * displacement.x
569	        newPoint.y += by * displacement.y
570	        displacement = direction(diff: nextPoint - point)
571	        newPoint.x += by * displacement.x
572	        newPoint.y += by * displacement.y
573	        results[i] = newPoint
574	      }
575	      return results
576	    } else {
577	      return vertex
578	    }
579	  }
