581	  func expandHighlightWidth(rect: NSRect, extraSurrounding: CGFloat) -> NSRect {
582	    var newRect = rect
583	    if !nearEmpty(newRect) {
584	      newRect.size.width += extraSurrounding
585	      newRect.origin.x -= extraSurrounding / 2
586	    }
587	    return newRect
588	  }
