590	  func removeCorner(highlightedPoints: [CGPoint], rightCorners: Set<Int>, containingRect: NSRect) -> Set<Int> {
591	    if !highlightedPoints.isEmpty && !rightCorners.isEmpty {
592	      var result = rightCorners
593	      for cornerIndex in rightCorners {
594	        let corner = highlightedPoints[cornerIndex]
595	        let dist = min(containingRect.maxY - corner.y, corner.y - containingRect.minY)
596	        if dist < 1e-2 {
597	          result.remove(cornerIndex)
598	        }
599	      }
600	      return result
601	    } else {
602	      return rightCorners
603	    }
604	  }
