606	  // swiftlint:disable:next large_tuple
607	  func linearMultilineFor(body: NSRect, leading: NSRect, trailing: NSRect) -> (Array<NSPoint>, Array<NSPoint>, Set<Int>, Set<Int>) {
608	    let highlightedPoints, highlightedPoints2: [NSPoint]
609	    let rightCorners, rightCorners2: Set<Int>
610	    if nearEmpty(body) && !nearEmpty(leading) && !nearEmpty(trailing) && trailing.maxX < leading.minX {
611	      highlightedPoints = rectVertex(of: leading)
612	      highlightedPoints2 = rectVertex(of: trailing)
613	      rightCorners = [2, 3]
614	      rightCorners2 = [0, 1]
615	    } else {
616	      highlightedPoints = multilineVertex(leadingRect: leading, bodyRect: body, trailingRect: trailing)
617	      highlightedPoints2 = []
618	      rightCorners = []
619	      rightCorners2 = []
620	    }
621	    return (highlightedPoints, highlightedPoints2, rightCorners, rightCorners2)
622	  }
623	
624	  func drawPath(highlightedRange: NSRange, backgroundRect: NSRect, preeditRect: NSRect, containingRect: NSRect, extraExpansion: Double) -> CGPath? {
625	    let theme = currentTheme
626	    let resultingPath: CGMutablePath?
627	
628	    var currentContainingRect = containingRect
629	    currentContainingRect.size.width += extraExpansion * 2
630	    currentContainingRect.size.height += extraExpansion * 2
631	    currentContainingRect.origin.x -= extraExpansion
632	    currentContainingRect.origin.y -= extraExpansion
633	
634	    let halfLinespace = theme.linespace / 2
635	    var innerBox = backgroundRect
636	    innerBox.size.width -= (theme.edgeInset.width + 1) * 2 - 2 * extraExpansion
637	    innerBox.origin.x += theme.edgeInset.width + 1 - extraExpansion
638	    innerBox.size.height += 2 * extraExpansion
639	    innerBox.origin.y -= extraExpansion
640	    if preeditRange.length == 0 {
641	      innerBox.origin.y += theme.edgeInset.height + 1
642	      innerBox.size.height -= (theme.edgeInset.height + 1) * 2
643	    } else {
644	      innerBox.origin.y += preeditRect.size.height + theme.preeditLinespace / 2 + theme.hilitedCornerRadius / 2 + 1
645	      innerBox.size.height -= theme.edgeInset.height + preeditRect.size.height + theme.preeditLinespace / 2 + theme.hilitedCornerRadius / 2 + 2
646	    }
647	    innerBox.size.height -= theme.linespace
648	    innerBox.origin.y += halfLinespace
649	
650	    var outerBox = backgroundRect
651	    outerBox.size.height -= preeditRect.size.height + max(0, theme.hilitedCornerRadius + theme.borderLineWidth) - 2 * extraExpansion
652	    outerBox.size.width -= max(0, theme.hilitedCornerRadius + theme.borderLineWidth)  - 2 * extraExpansion
653	    outerBox.origin.x += max(0.0, theme.hilitedCornerRadius + theme.borderLineWidth) / 2.0 - extraExpansion
654	    outerBox.origin.y += preeditRect.size.height + max(0, theme.hilitedCornerRadius + theme.borderLineWidth) / 2 - extraExpansion
655	
656	    let effectiveRadius = max(0, theme.hilitedCornerRadius + 2 * extraExpansion / theme.hilitedCornerRadius * max(0, theme.cornerRadius - theme.hilitedCornerRadius))
657	
658	    if theme.linear, let highlightedTextRange = convert(range: highlightedRange) {
659	      let (leadingRect, bodyRect, trailingRect) = multilineRects(forRange: highlightedTextRange, extraSurounding: separatorWidth, bounds: outerBox)
660	      var (highlightedPoints, highlightedPoints2, rightCorners, rightCorners2) = linearMultilineFor(body: bodyRect, leading: leadingRect, trailing: trailingRect)
661	
662	      highlightedPoints = enlarge(vertex: highlightedPoints, by: extraExpansion)
663	      highlightedPoints = expand(vertex: highlightedPoints, innerBorder: innerBox, outerBorder: outerBox)
664	      rightCorners = removeCorner(highlightedPoints: highlightedPoints, rightCorners: rightCorners, containingRect: currentContainingRect)
665	      resultingPath = drawSmoothLines(highlightedPoints, straightCorner: rightCorners, alpha: 0.3*effectiveRadius, beta: 1.4*effectiveRadius)?.mutableCopy()
666	
667	      if highlightedPoints2.count > 0 {
668	        highlightedPoints2 = enlarge(vertex: highlightedPoints2, by: extraExpansion)
669	        highlightedPoints2 = expand(vertex: highlightedPoints2, innerBorder: innerBox, outerBorder: outerBox)
670	        rightCorners2 = removeCorner(highlightedPoints: highlightedPoints2, rightCorners: rightCorners2, containingRect: currentContainingRect)
671	        let highlightedPath2 = drawSmoothLines(highlightedPoints2, straightCorner: rightCorners2, alpha: 0.3*effectiveRadius, beta: 1.4*effectiveRadius)
672	        if let highlightedPath2 = highlightedPath2 {
673	          resultingPath?.addPath(highlightedPath2)
674	        }
675	      }
676	    } else if let highlightedTextRange = convert(range: highlightedRange) {
677	      var highlightedRect = self.contentRect(range: highlightedTextRange)
678	      if !nearEmpty(highlightedRect) {
679	        highlightedRect.size.width = backgroundRect.size.width
680	        highlightedRect.size.height += theme.linespace
681	        highlightedRect.origin = NSPoint(x: backgroundRect.origin.x, y: highlightedRect.origin.y + theme.edgeInset.height - halfLinespace)
682	        if highlightedRange.upperBound == (textView.string as NSString).length {
683	          highlightedRect.size.height += theme.edgeInset.height - halfLinespace
684	        }
685	        if highlightedRange.location - (preeditRange == .empty ? 0 : preeditRange.upperBound) <= 1 {
686	          if preeditRange.length == 0 {
687	            highlightedRect.size.height += theme.edgeInset.height - halfLinespace
688	            highlightedRect.origin.y -= theme.edgeInset.height - halfLinespace
689	          } else {
690	            highlightedRect.size.height += theme.hilitedCornerRadius / 2
691	            highlightedRect.origin.y -= theme.hilitedCornerRadius / 2
692	          }
693	        }
694	
695	        var highlightedPoints = rectVertex(of: highlightedRect)
696	        highlightedPoints = enlarge(vertex: highlightedPoints, by: extraExpansion)
697	        highlightedPoints = expand(vertex: highlightedPoints, innerBorder: innerBox, outerBorder: outerBox)
698	        resultingPath = drawSmoothLines(highlightedPoints, straightCorner: Set(), alpha: effectiveRadius*0.3, beta: effectiveRadius*1.4)?.mutableCopy()
699	      } else {
700	        resultingPath = nil
701	      }
702	    } else {
703	      resultingPath = nil
704	    }
705	    return resultingPath
706	  }
707	
708	  func carveInset(rect: NSRect) -> NSRect {
709	    var newRect = rect
710	    newRect.size.height -= (currentTheme.hilitedCornerRadius + currentTheme.borderWidth) * 2
711	    newRect.size.width -= (currentTheme.hilitedCornerRadius + currentTheme.borderWidth) * 2
712	    newRect.origin.x += currentTheme.hilitedCornerRadius + currentTheme.borderWidth
713	    newRect.origin.y += currentTheme.hilitedCornerRadius + currentTheme.borderWidth
714	    return newRect
715	  }
716	
717	  func triangle(center: NSPoint, radius: CGFloat) -> [NSPoint] {
718	    [NSPoint(x: center.x, y: center.y + radius),
719	     NSPoint(x: center.x + 0.5 * sqrt(3) * radius, y: center.y - 0.5 * radius),
720	     NSPoint(x: center.x - 0.5 * sqrt(3) * radius, y: center.y - 0.5 * radius)]
721	  }
722	
723	  func pagingLayer(theme: SquirrelTheme, preeditRect: CGRect) -> (CAShapeLayer, CGPath?, CGPath?) {
724	    let layer = CAShapeLayer()
725	    guard theme.showPaging && (canPageUp || canPageDown) else { return (layer, nil, nil) }
726	    guard let firstCandidate = candidateRanges.first, let range = convert(range: firstCandidate) else { return (layer, nil, nil) }
727	    var height = contentRect(range: range).height
728	    let preeditHeight = max(0, preeditRect.height + theme.preeditLinespace / 2 + theme.hilitedCornerRadius / 2 - theme.edgeInset.height) + theme.edgeInset.height - theme.linespace / 2
729	    height += theme.linespace
730	    let radius = min(0.5 * theme.pagingOffset, 2 * height / 9)
731	    let effectiveRadius = min(theme.cornerRadius, 0.6 * radius)
732	    guard let trianglePath = drawSmoothLines(
733	      triangle(center: .zero, radius: radius),
734	      straightCorner: [], alpha: 0.3 * effectiveRadius, beta: 1.4 * effectiveRadius
735	    ) else {
736	      return (layer, nil, nil)
737	    }
738	    var downPath: CGPath?
739	    var upPath: CGPath?
740	    if canPageDown {
741	      var downTransform = CGAffineTransform(translationX: 0.5 * theme.pagingOffset, y: 2 * height / 3 + preeditHeight)
742	      let downLayer = shapeFromPath(path: trianglePath.copy(using: &downTransform))
743	      downLayer.fillColor = theme.backgroundColor.cgColor
744	      downPath = trianglePath.copy(using: &downTransform)
745	      layer.addSublayer(downLayer)
746	    }
747	    if canPageUp {
748	      var upTransform = CGAffineTransform(rotationAngle: .pi).translatedBy(x: -0.5 * theme.pagingOffset, y: -height / 3 - preeditHeight)
749	      let upLayer = shapeFromPath(path: trianglePath.copy(using: &upTransform))
750	      upLayer.fillColor = theme.backgroundColor.cgColor
751	      upPath = trianglePath.copy(using: &upTransform)
752	      layer.addSublayer(upLayer)
753	    }
754	    return (layer, downPath, upPath)
755	  }
756	}
